ST.xhtml:
open := (isOpen AND (NOT(isClosed))) AND superState;
closed := (isClosed AND (NOT(isOpen))) AND superState;
partiallyOpen := (NOT(isOpen OR isClosed)) AND superState;
undefined := (isOpen AND isClosed) AND superState;

good := (isGood AND (NOT(hasWarning))) AND superState;
warning := (isGood AND hasWarning) AND superState;
bad := (NOT(isGood)) AND superState;

shutdown := (state = InitializationStates.SHUTDOWN) AND superState;
initializing := (state = InitializationStates.INITIALIZING) AND superState;
initializingFailed := (state = InitializationStates.INITIALIZING_FAILED) AND superState;
initialized := (state = InitializationStates.INITIALIZED) AND superState;
locked := (state = InitializationStates.LOCKED) AND superState;

forward := (actVel > (ABS(tolerance))) AND superState;
backward := (actVel < (-(ABS(tolerance)))) AND superState;
standstill := (NOT(forward OR backward)) AND superState;

disabled := (NOT(config.enabled)) AND superState;
hiHi := (config.enabled AND (value >= config.hiHi)) AND superState;
hi := (config.enabled AND ((value >= config.hi) AND (value < config.hiHi))) AND superState;
ok := (config.enabled AND ((value > config.lo) AND (value < config.hi))) AND superState;
lo := (config.enabled AND ((value <= config.lo) AND (value < config.loLo))) AND superState;
loLo := (config.enabled AND (value <= config.loLo)) AND superState;

opening := (isOpening AND (NOT(isClosing))) AND superState;
closing := (isClosing AND (NOT(isOpening))) AND superState;
standstill := (NOT(isClosing OR isOpening)) AND superState;

none := (state = OperatorStates.NONE) AND superState;
tech := (state = OperatorStates.TECH) AND superState;
observer := (state = OperatorStates.OBSERVER) AND superState;

moving := (isAwake AND isMoving) AND superState;
awake := (isAwake AND (NOT(isMoving))) AND superState;
sleeping := (NOT(isAwake)) AND superState;

radians(
    value := newDegreesValue * 0.017453292519943295,
    unit := Units.RADIAN);
degrees(
    value := newDegreesValue,
    unit := Units.DEGREE);
arcseconds(
    value := newDegreesValue * 3600.0,
    unit := Units.ARCSECONDS);

millimeters(
    value := newMillimetersValue,
    unit := Units.MILLIMETER);
micrometers(
    value := newMillimetersValue * 1000.0,
    unit := Units.MICROMETER);

radiansPerSecond(
    value := newDegreesPerSecondValue * 0.017453292519943295,
    unit := Units.RADIANS_PER_SECOND);
degreesPerSecond(
    value := newDegreesPerSecondValue,
    unit := Units.DEGREES_PER_SECOND);
arcsecondsPerSecond(
    value := newDegreesPerSecondValue * 3600.0,
    unit := Units.ARCSECONDS_PER_SECOND);

radiansPerSquareSecond(
    value := newDegreesPerSquareSecondValue * 0.017453292519943295,
    unit := Units.RADIANS_PER_SQUARE_SECOND);
degreesPerSquareSecond(
    value := newDegreesPerSquareSecondValue,
    unit := Units.DEGREES_PER_SQUARE_SECOND);
arcsecondsPerSquareSecond(
    value := newDegreesPerSquareSecondValue * 3600.0,
    unit := Units.ARCSECONDS_PER_SQUARE_SECOND);

millimetersPerSecond(
    value := newMillimetersPerSecondValue,
    unit := Units.MILLIMETERS_PER_SECOND);

volt(
    value := newVoltValue,
    unit := Units.VOLT);
milliVolt(
    value := newVoltValue * 1000.0,
    unit := Units.MILLIVOLT);

g(
    value := newMilliGValue / 1000.0,
    unit := Units.G);
milliG(
    value := newMilliGValue,
    unit := Units.MILLIG);

amps(
    value := newAmpsValue,
    unit := Units.AMPS);
milliAmps(
    value := newAmpsValue * 1000.0,
    unit := Units.MILLIAMPS);

newtonmeter(
    value := newNewtonmeterValue,
    unit := Units.NEWTONMETER);

unitless(
    value := newFractionValue,
    unit := Units.UNITLESS);
percent(
    value := newFractionValue * 100.0,
    unit := Units.PERCENT);
newtonmeter(
    value := newFractionValue * maxNewtonmeter,
    unit := Units.NEWTONMETER);

seconds(
    value := newSecondsValue,
    unit := Units.SECONDS);
minutes(
    value := newSecondsValue / 60.0,
    unit := Units.MINUTES);

celsius(
    value := newCelsiusValue,
    unit := Units.DEGREES_CELSIUS);
kelvin(
    value := newCelsiusValue + 273.15,
    unit := Units.KELVIN);

bar(
    value := newBarValue,
    unit := Units.BAR);
pascal(
    value := newBarValue * 100000.0,
    unit := Units.PASCAL);

hertz(
    value := newHertzValue,
    unit := Units.HERTZ);

newton(
    value := newNewtonValue,
    unit := Units.NEWTON);
decaNewton(
    value := newNewtonValue / 10.0,
    unit := Units.DECANEWTON);

unitless(
    value := newFractionValue,
    unit := Units.UNITLESS);
percent(
    value := newFractionValue * 100.0,
    unit := Units.PERCENT);

