IF do_request THEN
    start();
    do_request := False;
END_IF;
SUPER^();

IF THIS^.statuses.enabledStatus.enabled THEN
    THIS^.start();
    request := RequestResults.ACCEPTED;
ELSE
    request := RequestResults.ACCEPTED;
END_IF;

